import { Router } from "express";
import { authMiddleware } from "../../middleware/auth.js";
import VideoProjectController from "../../controller/video-project.controller.js";
import VideoProjectService from "../../service/video-project.service.js";
import VideoProjectRepository from "../../repository/video-project.repository.js";
import ContentRepository from "../../repository/content.repository.js";
import PackagingRepository from "../../repository/packaging.repository.js";
const router = Router();
const videoProjectRepo = new VideoProjectRepository();
const contentRepo = new ContentRepository();
const packagingRepo = new PackagingRepository();
const videoProjectService = new VideoProjectService(videoProjectRepo, contentRepo, packagingRepo);
const videoProjectController = new VideoProjectController(videoProjectService);
router.use(authMiddleware);
router.post("/", videoProjectController.create);
router.get("/", videoProjectController.list);
router.get("/:projectId", videoProjectController.getById);
router.patch("/:projectId", videoProjectController.update);
router.delete("/:projectId", videoProjectController.delete);
router.patch("/:projectId/step/:stepName/start", videoProjectController.startStep);
router.patch("/:projectId/step/:stepName/complete", videoProjectController.completeStep);
router.patch("/:projectId/link/:resourceType", videoProjectController.linkResource);
export default router;
